mapper.select:
select * from `exam_qualification`

     and id = #{id}

order by id desc

mapper.update:
update `exam_qualification`
exam_id = #{examId}, student_id = #{studentId}, attendance_count = #{attendanceCount}, required_count = #{requiredCount}, qualification_rate = #{qualificationRate}, is_qualified = #{isQualified}, reason = #{reason}, create_time = #{createTime},
where id = #{id}
